export const MLRO_PREFIX_BY_ID: Map<string, MlroPrefix> = new Map(MLRO_PREFIXES.map((m) => [m.id, m]));
export const MLRO_QUESTION_BY_ID: Map<string, MlroQuestionTemplate> = new Map(MLRO_QUESTION_TEMPLATES.map((m) => [m.id, m]));

export function prefixFor(id: string): string | undefined {
  return MLRO_PREFIX_BY_ID.get(id)?.prefix;
}

export function questionFor(id: string): string | undefined {
  return MLRO_QUESTION_BY_ID.get(id)?.question;
}
